const allRows = $input.all();
const now     = new Date();
const todayMs = now.getTime();
const sevenDaysMs = 7 * 24 * 60 * 60 * 1000;

const due = [];
for (const r of allRows) {
  const v = r.json;
  if ((v.reminderSent || '').toLowerCase() === 'yes') continue;
  if ((v.status      || '').toLowerCase() === 'booked') continue;
  if (!v.phone) continue;

  let isDue = false; let urgency = 'normal';

  if (v.nextServiceDate) {
    try {
      const diff = new Date(v.nextServiceDate).getTime() - todayMs;
      if (diff <= sevenDaysMs) { isDue = true; urgency = diff < 0 ? 'overdue' : diff <= 2*86400000 ? 'critical' : 'normal'; }
    } catch(e) {}
  }
  const curKm  = parseFloat(v.currentMileage || 0);
  const nextKm = parseFloat(v.nextServiceMileage || 0);
  if (nextKm > 0 && (nextKm - curKm) <= 500) { isDue = true; if (curKm >= nextKm) urgency = 'overdue'; }

  if (!isDue) continue;

  const urgencyLine = { overdue:'вљ пёЏ *OVERDUE* вЂ” Please book immediately!', critical:'рџ”ґ *Due in 1вЂ“2 days* вЂ” Book now!', normal:'рџ”” Service due soon' }[urgency];
  const dateStr  = v.nextServiceDate ? new Date(v.nextServiceDate).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'}) : 'Not set';
  const kmLine   = nextKm > 0 ? `рџ›ЈпёЏ Next service: *${parseInt(nextKm).toLocaleString()} km*  (now: *${parseInt(curKm).toLocaleString()} km*)` : '';

  const msg = [
    `рџ”§ *Service Reminder вЂ” ${v.vehicleReg || 'Your Vehicle'}*`,
    `рџ‘¤ Hi *${v.ownerName || 'Owner'}!*`, '',
    `рџљ— ${v.make||''} ${v.model||''} ${v.year||''} В· *${v.vehicleReg||''}*`,
    urgencyLine, '',
    `рџ“… Date due: *${dateStr}*`, kmLine, '',
    'в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ',
    'Reply *book* в†’ schedule an appointment',
    'Reply *status* в†’ view vehicle details',
    'Reply *history* в†’ view past services'
  ].filter(Boolean).join('\n');

  due.push({ json: { phone: v.phone, vehicleReg: v.vehicleReg, ownerName: v.ownerName, urgency, reminderMsg: msg } });
}
if (due.length === 0) return [{ json: { message: 'No vehicles due today', count: 0 } }];
return due;

const rows = $input.all();
const now  = new Date();
const tom  = new Date(now); tom.setDate(tom.getDate() + 1);
const tomStr = tom.toISOString().split('T')[0];
const due = rows.filter(r => (r.json.appointmentDate||'').split('T')[0] === tomStr && (r.json.status||'').toLowerCase() === 'confirmed');
if (due.length === 0) return [{ json: { message: 'No appointments tomorrow' } }];
return due.map(r => ({ json: {
  phone: r.json.phone,
  msg: `рџ“… *Appointment Reminder*\n\nYour service is *tomorrow!*\nрџљ— Reg: *${r.json.vehicleReg}*\nрџ”§ ${r.json.serviceType || 'General Service'}\nвЏ° *${r.json.timeSlot}*\n\nPlease arrive 10 min early.\nReply *cancel* to reschedule.`
}}));

const phone   =  $('Wati Trigger').first().json.waId|| $('Wati Trigger1').item.json.from;
const allRows = $input.all();
const vehicle = allRows.find(r => (r.json.phone||'') === phone);
if (!vehicle) return [{ json: { phone, bookingMsg: 'вљ пёЏ No vehicle found. Contact the service centre to register.' }}];
const v = vehicle.json;
const now = new Date();
const slots = [];
let day = new Date(now); day.setDate(day.getDate() + 1);
const times = ['10:00 AM', '02:00 PM'];
while (slots.length < 4) {
  const dow = day.getDay();
  if (dow !== 0 && dow !== 6) {
    for (const t of times) {
      if (slots.length < 4) {
        const label = day.toLocaleDateString('en-IN',{weekday:'short',day:'numeric',month:'short'});
        slots.push({ label: `${slots.length+1}\ufe0f\u20e3  ${label} вЂ“ ${t}`, date: day.toISOString().split('T')[0], time: t });
      }
    }
  }
  day = new Date(day); day.setDate(day.getDate() + 1);
}
const msg = [`рџ”§ *Book a Service Appointment*`,`рџљ— ${v.make} ${v.model} В· *${v.vehicleReg}*`,``,`рџ“… *Choose a slot:*`,...slots.map(s=>s.label),``,`Reply *1*, *2*, *3* or *4* to confirm.`].join('\n');
return [{ json: { phone, vehicleReg: v.vehicleReg, make: v.make, model: v.model, ownerName: v.ownerName, bookingMsg: msg }}];

const phone    = $('Wati Trigger').item.json.waId || $('Wati Trigger1').item.json.from;
const text     = ($('Wati Trigger').item.json.text || '').trim();
const choice   = parseInt(text.replace(/^confirm\s*/i,'').trim());
const allRows  = $input.all();
const vehicle  = allRows.find(r => (r.json.phone||'') === phone);
if (!vehicle) return [{ json: { phone, confirmMsg: 'вљ пёЏ Vehicle not found. Contact the service centre.' }}];
if (isNaN(choice) || choice < 1 || choice > 4) return [{ json: { phone, confirmMsg: 'вљ пёЏ Reply *confirm 1*, *confirm 2*, *confirm 3* or *confirm 4* to pick a slot.\n\nSend *book* to see slots again.' }}];
const v = vehicle.json;
const now = new Date();
const slots = [];
let day = new Date(now); day.setDate(day.getDate() + 1);
const times = ['10:00 AM', '02:00 PM'];
while (slots.length < 4) {
  const dow = day.getDay();
  if (dow !== 0 && dow !== 6) {
    for (const t of times) { if (slots.length < 4) { slots.push({ date: day.toISOString().split('T')[0], time: t }); } }
  }
  day = new Date(day); day.setDate(day.getDate() + 1);
}
const chosen  = slots[choice - 1];
const apptId  = `APT-${phone}-${Date.now()}`;
const dateLabel = new Date(chosen.date).toLocaleDateString('en-IN',{weekday:'long',day:'numeric',month:'long'});
const confirmMsg = [`вњ… *Appointment Confirmed!*`,``,`рџ“… *${dateLabel}*`,`вЏ° Time: *${chosen.time}*`,`рџљ— ${v.make} ${v.model} В· *${v.vehicleReg}*`,`рџ”§ Full Service`,``,`We'll remind you the day before. See you then! рџ™Њ`,``,`Reply *history* to view past services.`].join('\n');
return [{ json: { phone, vehicleReg: v.vehicleReg, ownerName: v.ownerName, apptId, appointmentDate: chosen.date, timeSlot: chosen.time, serviceType: 'Full Service', bookedAt: now.toISOString(), confirmMsg }}];

const phone  = $('Wati Trigger').first().json.waId || $('Wati Trigger1').item.json.from;
const text   = ($('Wati Trigger').first().json.text || '').trim();
const newKm  = parseFloat(text.split(/\s+/)[1] || '0');
if (!newKm || newKm <= 0) return [{ json: { phone, milMsg: 'вљ пёЏ Format: *mileage <km>*\nExample: *mileage 51650*' }}];
const allRows = $input.all();
const vehicle = allRows.find(r => (r.json.phone||'') === phone);
if (!vehicle) return [{ json: { phone, milMsg: 'вљ пёЏ No vehicle registered. Contact the service centre.' }}];
const v          = vehicle.json;
const intervalKm = parseFloat(v.serviceIntervalKm || 5000);
const lastKm     = parseFloat(v.lastServiceMileage || 0);
const nextKm     = lastKm + intervalKm;
const kmLeft     = nextKm - newKm;
const isOverdue  = newKm >= nextKm;
const urgencyLine = isOverdue
  ? `вљ пёЏ *Overdue!* ${Math.abs(Math.round(kmLeft)).toLocaleString()} km past service point!`
  : kmLeft <= 500 ? `рџ”ґ Only *${Math.round(kmLeft).toLocaleString()} km* left вЂ” book soon!`
  : `вњ… Next service in *${Math.round(kmLeft).toLocaleString()} km*`;
const milMsg = [`рџ“Џ *Mileage Updated*`,`рџљ— ${v.make} ${v.model} В· ${v.vehicleReg}`,``,`рџ›ЈпёЏ Current: *${newKm.toLocaleString()} km*`,`рџ›ЈпёЏ Next service at: *${nextKm.toLocaleString()} km*`,urgencyLine,``,isOverdue || kmLeft <= 500 ? `Reply *book* to schedule now рџ”§` : `Keep it up! рџљ—`].join('\n');
return [{ json: { phone, vehicleReg: v.vehicleReg, currentMileage: newKm, nextServiceMileage: nextKm, newStatus: isOverdue ? 'Overdue' : 'Active', milMsg }}];

const phone   = $('Wati Trigger').item.json.waId || $('Wati Trigger1').item.json.from;
const records = $input.all().filter(r => (r.json.phone||'') === phone)
  .sort((a,b) => new Date(b.json.serviceDate) - new Date(a.json.serviceDate)).slice(0,5);
if (records.length === 0) return [{ json: { phone, histMsg: 'рџ”§ *No service history found.*\n\nOnce your vehicle is serviced, records appear here.' }}];
const lines = [`рџ“‹ *Service History*`,``];
for (const r of records) {
  const dt   = r.json.serviceDate ? new Date(r.json.serviceDate).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'}) : 'вЂ”';
  const km   = r.json.mileageAtService ? parseInt(r.json.mileageAtService).toLocaleString() + ' km' : 'вЂ”';
  const cost = r.json.cost ? `в‚№${parseFloat(r.json.cost).toLocaleString()}` : 'вЂ”';
  lines.push(`рџ”§ *${dt}* В· ${km}`);
  lines.push(`   ${r.json.serviceType || 'Service'}: ${r.json.workDone || 'вЂ”'}`);
  lines.push(`   Cost: ${cost}`); lines.push('');
}
lines.push('в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ'); lines.push('Reply *book* to schedule your next service.');
return [{ json: { phone, histMsg: lines.join('\n') } }];

const phone   = $('Wati Trigger').item.json.waId || $('Wati Trigger1').item.json.from;
const v = $input.all().find(r => (r.json.phone||'') === phone);
if (!v) return [{ json: { phone, statusMsg: 'вљ пёЏ No vehicle registered.\nContact the service centre.' }}];
const rec    = v.json;
const nextDt = rec.nextServiceDate ? new Date(rec.nextServiceDate).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'}) : 'Not set';
const lastDt = rec.lastServiceDate ? new Date(rec.lastServiceDate).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'}) : 'Not yet serviced';
const badge  = {active:'вњ…',overdue:'рџ”ґ',booked:'рџ“…'}[(rec.status||'active').toLowerCase()] || 'вњ…';
const msg = [`рџљ— *Vehicle Status*`,``,`рџ”µ *${rec.make||''} ${rec.model||''} ${rec.year||''}*`,`рџ”µ Reg: *${rec.vehicleReg||'вЂ”'}*`,`рџ”µ Owner: ${rec.ownerName||'вЂ”'}`,``,`${badge} Status: *${rec.status||'Active'}*`,`рџ›ЈпёЏ Current: *${parseInt(rec.currentMileage||0).toLocaleString()} km*`,``,`рџ”§ *Next Service*`,`   рџ“… Date: *${nextDt}*`,`   рџ›ЈпёЏ At: *${parseInt(rec.nextServiceMileage||0).toLocaleString()} km*`,``,`рџ”§ *Last Service*`,`   рџ“… ${lastDt}`,``,`в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`,`Reply *book* to schedule В· *history* for records`].join('\n');
return [{ json: { phone, statusMsg: msg } }];

const phone = $json.waId || $json.from;
const text  = ($json.text || '').replace(/^logservice\s+/i,'').trim();
const parts = text.split(/\s+/);
if (parts.length < 4) return [{ json: { phone, errMsg: 'вљ пёЏ Format: *logservice <reg> <km> <work> <cost>*\nExample: *logservice MH12AB3456 52000 Oil change 2500*' }}];
const reg    = parts[0].toUpperCase();
const km     = parseFloat(parts[1]) || 0;
const cost   = parseFloat(parts[parts.length-1]) || 0;
const work   = parts.slice(2,parts.length-1).join(' ');
const now    = new Date();
const nextDt = new Date(now); nextDt.setDate(nextDt.getDate() + 180);
return [{ json: { phone, reg, km, cost, work, historyId: `SH-${reg}-${now.getTime()}`, serviceDate: now.toISOString().split('T')[0], recordedAt: now.toISOString(), nextServiceDate: nextDt.toISOString().split('T')[0], logMsg: `вњ… *Service Logged*\nрџљ— ${reg}\nрџ›ЈпёЏ At ${km.toLocaleString()} km\nрџ”§ ${work}\nрџ’° в‚№${cost.toLocaleString()}` }}];
